const input = $input.first().json;
const workflowName = String(input.workflowName || 'RAG Workflow');
const ingestPathRaw = String(input.ingestPath || 'my-rag-ingest');
const queryPathRaw = String(input.queryPath || 'my-rag-query');
const description = String(input.description || 'Two-webhook RAG: Ollama nomic-embed-text + Supabase pgvector match_documents + llama3.2:3b chat.');

function sanitizePath(p) {
  return p.replace(/^\/+/, '').replace(/[^a-z0-9_\-]/gi, '-').toLowerCase() || 'rag';
}
const ingestPath = sanitizePath(ingestPathRaw);
const queryPath = sanitizePath(queryPathRaw);

const safeName = workflowName.replace(/\\/g, '\\\\').replace(/"/g, '\\"');
const slug = workflowName.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '') || 'rag-workflow';

const anonJwt = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJyb2xlIjoiYW5vbiIsImlzcyI6InN1cGFiYXNlIiwiaWF0IjoxNzUxMDg2ODAwLCJleHAiOjE5MDg4NTMyMDB9.ZvEDn3ykbm4EzNHfU5SG7exKPD1HkK9w_760ZJa63OQ';

const sdkCode = `import { workflow, node, trigger } from "@n8n/workflow-sdk";

const ingestWebhook = trigger({
  type: "n8n-nodes-base.webhook",
  version: 2,
  config: {
    name: "Webhook Ingest",
    parameters: {
      httpMethod: "POST",
      path: "${ingestPath}",
      responseMode: "lastNode",
    },
  },
});

const queryWebhook = trigger({
  type: "n8n-nodes-base.webhook",
  version: 2,
  config: {
    name: "Webhook Query",
    parameters: {
      httpMethod: "POST",
      path: "${queryPath}",
      responseMode: "lastNode",
    },
  },
});

const ingestPrepare = node({
  type: "n8n-nodes-base.code",
  version: 2,
  config: {
    name: "Ingest Prepare",
    parameters: {
      mode: "runOnceForAllItems",
      jsCode: "const root = $input.first().json;\\nconst body = root.body ?? root;\\nconst content = String(body.content ?? '').trim();\\nconst metadata = body.metadata ?? {};\\nif (!content) throw new Error('Missing content');\\nreturn [{ json: { content, metadata } }];",
    },
  },
});

const ingestEmbed = node({
  type: "n8n-nodes-base.httpRequest",
  version: 4.2,
  config: {
    name: "Ingest Ollama Embed",
    parameters: {
      method: "POST",
      url: "http://ollama:11434/api/embeddings",
      sendHeaders: true,
      headerParameters: { parameters: [{ name: "Content-Type", value: "application/json" }] },
      sendBody: true,
      specifyBody: "json",
      jsonBody: "={{ JSON.stringify({ model: 'nomic-embed-text', prompt: $json.content }) }}",
      options: { response: { response: { fullResponse: true, neverError: true } } },
    },
  },
});

const ingestBuildRow = node({
  type: "n8n-nodes-base.code",
  version: 2,
  config: {
    name: "Ingest Build Row",
    parameters: {
      mode: "runOnceForAllItems",
      jsCode: "const prep = $('Ingest Prepare').first().json;\\nconst http = $input.first().json;\\nconst raw = http.body ?? http.data ?? '{}';\\nconst body = typeof raw === 'string' ? JSON.parse(raw) : raw;\\nconst embedding = body.embedding ?? [];\\nreturn [{ json: { content: prep.content, metadata: prep.metadata ?? {}, embedding } }];",
    },
  },
});

const ingestInsert = node({
  type: "n8n-nodes-base.httpRequest",
  version: 4.2,
  config: {
    name: "Ingest Supabase Insert",
    parameters: {
      method: "POST",
      url: "http://kong:8000/rest/v1/documents",
      sendHeaders: true,
      headerParameters: {
        parameters: [
          { name: "Content-Type", value: "application/json" },
          { name: "apikey", value: "${anonJwt}" },
          { name: "Authorization", value: "Bearer ${anonJwt}" },
          { name: "Prefer", value: "return=representation" },
        ],
      },
      sendBody: true,
      specifyBody: "json",
      jsonBody: "={{ JSON.stringify({ content: $json.content, embedding: $json.embedding, metadata: $json.metadata }) }}",
      options: { response: { response: { fullResponse: true, neverError: true } } },
    },
  },
});

const ingestRespond = node({
  type: "n8n-nodes-base.code",
  version: 2,
  config: {
    name: "Ingest Format Response",
    parameters: {
      mode: "runOnceForAllItems",
      jsCode: "const prep = $('Ingest Prepare').first().json;\\nconst http = $input.first().json;\\nconst raw = http.body ?? http.data ?? '[]';\\nconst rows = Array.isArray(typeof raw === 'string' ? JSON.parse(raw) : raw) ? (typeof raw === 'string' ? JSON.parse(raw) : raw) : [];\\nreturn [{ json: { ok: (http.statusCode ?? 0) >= 200 && (http.statusCode ?? 0) < 300, id: rows[0]?.id, content: prep.content } }];",
    },
  },
});

const queryPrepare = node({
  type: "n8n-nodes-base.code",
  version: 2,
  config: {
    name: "Query Prepare",
    parameters: {
      mode: "runOnceForAllItems",
      jsCode: "const root = $input.first().json;\\nconst body = root.body ?? root;\\nconst question = String(body.question ?? '').trim();\\nif (!question) throw new Error('Missing question');\\nconst mc = typeof body.match_count === 'number' ? body.match_count : 5;\\nconst mt = typeof body.match_threshold === 'number' ? body.match_threshold : 0.5;\\nconst sessionId = body.sessionId != null ? String(body.sessionId) : `rag-${Date.now()}`;\\nreturn [{ json: { question, match_count: Math.max(1, Math.floor(mc)), match_threshold: mt, sessionId } }];",
    },
  },
});

const queryEmbed = node({
  type: "n8n-nodes-base.httpRequest",
  version: 4.2,
  config: {
    name: "Query Ollama Embed",
    parameters: {
      method: "POST",
      url: "http://ollama:11434/api/embeddings",
      sendHeaders: true,
      headerParameters: { parameters: [{ name: "Content-Type", value: "application/json" }] },
      sendBody: true,
      specifyBody: "json",
      jsonBody: "={{ JSON.stringify({ model: 'nomic-embed-text', prompt: $json.question }) }}",
      options: { response: { response: { fullResponse: true, neverError: true } } },
    },
  },
});

const queryMatch = node({
  type: "n8n-nodes-base.httpRequest",
  version: 4.2,
  config: {
    name: "Query Match Documents",
    parameters: {
      method: "POST",
      url: "http://kong:8000/rest/v1/rpc/match_documents",
      sendHeaders: true,
      headerParameters: {
        parameters: [
          { name: "Content-Type", value: "application/json" },
          { name: "apikey", value: "${anonJwt}" },
          { name: "Authorization", value: "Bearer ${anonJwt}" },
        ],
      },
      sendBody: true,
      specifyBody: "json",
      jsonBody: "={{ (() => { let emb = []; try { const raw = $json.body ?? $json.data ?? '{}'; const b = typeof raw === 'string' ? JSON.parse(raw) : raw; emb = b.embedding ?? []; } catch (e) { emb = []; } const prep = $('Query Prepare').first().json; return JSON.stringify({ query_embedding: emb, match_count: prep.match_count, match_threshold: prep.match_threshold }); })() }}",
      options: { response: { response: { fullResponse: true, neverError: true } } },
    },
  },
});

const queryContext = node({
  type: "n8n-nodes-base.code",
  version: 2,
  config: {
    name: "Query Build Context",
    parameters: {
      mode: "runOnceForAllItems",
      jsCode: "const prep = $('Query Prepare').first().json;\\nconst http = $input.first().json;\\nconst raw = http.body ?? http.data ?? '[]';\\nconst matches = Array.isArray(typeof raw === 'string' ? JSON.parse(raw) : raw) ? (typeof raw === 'string' ? JSON.parse(raw) : raw) : [];\\nconst ctx = matches.map((m,i)=>'Source ' + (i+1) + ': ' + (m.content||'')).join('\\\\n\\\\n');\\nconst sources = matches.map(m => ({ id: m.id, similarity: m.similarity, metadata: m.metadata }));\\nreturn [{ json: { question: prep.question, sessionId: prep.sessionId, context: ctx, sources } }];",
    },
  },
});

const queryChat = node({
  type: "n8n-nodes-base.httpRequest",
  version: 4.2,
  config: {
    name: "Query Ollama Chat",
    parameters: {
      method: "POST",
      url: "http://ollama:11434/api/chat",
      sendHeaders: true,
      headerParameters: { parameters: [{ name: "Content-Type", value: "application/json" }] },
      sendBody: true,
      specifyBody: "json",
      jsonBody: "={{ JSON.stringify({ model: 'llama3.2:3b', stream: false, messages: [{ role: 'system', content: 'Answer using ONLY the context.\\n\\n' + $json.context }, { role: 'user', content: $json.question }] }) }}",
      options: { response: { response: { fullResponse: true, neverError: true } } },
    },
  },
});

const queryRespond = node({
  type: "n8n-nodes-base.code",
  version: 2,
  config: {
    name: "Query Format Response",
    parameters: {
      mode: "runOnceForAllItems",
      jsCode: "const ctx = $('Query Build Context').first().json;\\nconst http = $input.first().json;\\nconst raw = http.body ?? http.data ?? '{}';\\nconst body = typeof raw === 'string' ? JSON.parse(raw) : raw;\\nconst answer = String(body?.message?.content ?? '');\\nreturn [{ json: { ok: true, answer, sources: ctx.sources, sessionId: ctx.sessionId } }];",
    },
  },
});

export default workflow("${slug}", "${safeName}")
  .add(ingestWebhook)
  .to(ingestPrepare)
  .to(ingestEmbed)
  .to(ingestBuildRow)
  .to(ingestInsert)
  .to(ingestRespond)
  .add(queryWebhook)
  .to(queryPrepare)
  .to(queryEmbed)
  .to(queryMatch)
  .to(queryContext)
  .to(queryChat)
  .to(queryRespond);
`;

return [{
  json: {
    workflowName,
    ingestPath,
    queryPath,
    description,
    sdkCode,
    validateRpc: { jsonrpc: '2.0', id: 1, method: 'tools/call', params: { name: 'validate_workflow', arguments: { code: sdkCode } } },
    createRpc: { jsonrpc: '2.0', id: 2, method: 'tools/call', params: { name: 'create_workflow_from_code', arguments: { code: sdkCode, name: workflowName, description } } },
  },
}];

function parseMcpSse(raw) {
  const text = typeof raw === 'string' ? raw : String(raw ?? '');
  const dataLine = text.split(/\r?\n/).find((l) => l.startsWith('data: '));
  if (!dataLine) throw new Error('Invalid MCP validate response: ' + text.slice(0, 500));
  const payload = JSON.parse(dataLine.slice(6));
  if (payload.error) throw new Error(payload.error.message || JSON.stringify(payload.error));
  const t = payload.result?.content?.[0]?.text;
  return t ? JSON.parse(t) : (payload.result?.structuredContent || {});
}
const http = $input.first().json;
const v = parseMcpSse(http.body ?? http.data ?? '');
if (!v.valid) throw new Error('Workflow validation failed: ' + JSON.stringify(v));
const built = $('Build SDK Payload').first().json;
return [{ json: { ...built, validation: v } }];

function parseMcpSse(raw) {
  const text = typeof raw === 'string' ? raw : String(raw ?? '');
  const dataLine = text.split(/\r?\n/).find((l) => l.startsWith('data: '));
  if (!dataLine) throw new Error('Invalid MCP create response: ' + text.slice(0, 500));
  const payload = JSON.parse(dataLine.slice(6));
  if (payload.error) throw new Error(payload.error.message || JSON.stringify(payload.error));
  const t = payload.result?.content?.[0]?.text;
  return t ? JSON.parse(t) : (payload.result?.structuredContent || {});
}
const http = $input.first().json;
const created = parseMcpSse(http.body ?? http.data ?? '');
const built = $('Build SDK Payload').first().json;
const ingestUrl = `http://localhost:5678/webhook-test/${built.ingestPath}`;
const queryUrl = `http://localhost:5678/webhook-test/${built.queryPath}`;
return [{
  json: {
    success: true,
    workflowId: created.workflowId,
    name: created.name,
    url: created.url,
    nodeCount: created.nodeCount,
    ingestPath: built.ingestPath,
    queryPath: built.queryPath,
    ingestWebhookUrl: ingestUrl,
    queryWebhookUrl: queryUrl,
    response: `Created RAG workflow "${created.name}" (${created.nodeCount} nodes). Open ${created.url} to activate it, then POST ingest to ${ingestUrl} and query to ${queryUrl} (production webhooks use /webhook/... once active).`,
  },
}];
